// --- Hent profil ---
const trig = $items("When Executed by Another Workflow", 0, 0)?.[0]?.json ?? {};
const profile = trig.profile ?? trig;
const tabs = profile.connection?.tabs ?? {};
const headerRow = Number.isFinite(tabs.headerRow) ? Number(tabs.headerRow) : 1;

// --- Input fra Google Sheets-noden ---
// For enkelhet antar vi at hver rad kommer som ett item med et objekt (nøkkel=kolonnenavn hvis node’n gjør header-løft).
// Hvis du får rene arrays, kan vi håndtere det også (se lenger ned).
const items = $input.all();

// Verktøy: trim og normaliser header
function norm(s){ return String(s ?? '').trim(); }
function isColLetter(s){ return /^[A-Za-z]$/.test(String(s)); }
function colLetterToIndex(letter){ return letter.toUpperCase().charCodeAt(0) - 65; } // A=0,B=1,…

// --- Finn mapping ---
// 1) Hvis du har kolonnenavn (tabs.match / tabs.qty), bruk dem.
// 2) Hvis du har kolonnebokstaver (tabs.match_col / tabs.qty_col), bruk posisjoner.
// 3) Hvis ingenting spesifisert, prøv å autodetektere med enkle heuristikker ("sku", "ean", "id", "stock", "qty").

let keyRef = tabs.match;
let qtyRef = tabs.qty;
let keyCol = tabs.match_col;
let qtyCol = tabs.qty_col;

// Heuristikk hvis ikke angitt:
if (!keyRef && !keyCol) keyRef = 'sku';
if (!qtyRef && !qtyCol) qtyRef = 'stock';

// --- Les header hvis vi må (hvis input er arrays eller vi skal bruke bokstaver) ---
let header = null;
let rowsNormalized = [];

// Case A: Items allerede som objekter (vanlig når Sheets-noden bruker header)
const looksLikeObjects = items.length && typeof items[0].json === 'object' && !Array.isArray(items[0].json);

// Hvis vi må bruke bokstaver, eller vi vil verifisere header, bygg header fra første rad om mulig
if (!looksLikeObjects) {
  // Hvis du i stedet får arrays: bygg header fra headerRow
  // Forvent at Google Sheets-noden returnerer noe som ligner { values: [...] } eller rader som arrays;
  // Tilpass dette til din faktiske struktur hvis nødvendig.
  throw new Error('Forventet objekt-rader fra Sheets-noden. Sett noden til å bruke header-row eller map før.');
}

// Normaliser objekter og lag “header”-liste for evt. bokstavoppslag
// (Her antar vi at keys i json ER kolonnenavn hentet fra header-row)
header = Object.keys(items[0].json).map(norm);

// Funksjon for å hente feltverdi enten med kolonnenavn eller bokstav
function getVal(rowJson, refName, refCol) {
  // 1) navne-referanse
  if (refName) {
    // prøv eksakt, lower og upper
    const direct = rowJson[refName];
    if (direct !== undefined) return direct;
    const lowerKey = Object.keys(rowJson).find(k => k.toLowerCase() === String(refName).toLowerCase());
    if (lowerKey) return rowJson[lowerKey];
  }
  // 2) bokstav-referanse
  if (refCol && isColLetter(refCol)) {
    const idx = colLetterToIndex(refCol);
    const keys = Object.keys(rowJson);
    if (idx >= 0 && idx < keys.length) return rowJson[keys[idx]];
  }
  return undefined;
}

// Autodetect hvis fortsatt mangler (enkel heuristikk)
function autoDetectKey(rowJson) {
  const keys = Object.keys(rowJson);
  const hit = keys.find(k => /^(sku|ean|barcode|id)$/i.test(k.trim()));
  return hit ? { refName: hit } : null;
}
function autoDetectQty(rowJson) {
  const keys = Object.keys(rowJson);
  const hit = keys.find(k => /^(stock|qty|quantity|lager)$/i.test(k.trim()));
  return hit ? { refName: hit } : null;
}
if (!keyRef && !keyCol) {
  const guess = autoDetectKey(items[0].json);
  if (guess) keyRef = guess.refName;
}
if (!qtyRef && !qtyCol) {
  const guess = autoDetectQty(items[0].json);
  if (guess) qtyRef = guess.refName;
}

// --- Map alle rader til standard format ---
const out = [];
for (const { json: r } of items) {
  const keyVal = getVal(r, keyRef, keyCol);
  const qtyVal = getVal(r, qtyRef, qtyCol);
  if (keyVal == null || String(keyVal).trim() === '') continue;

  const qtyNum = Number(qtyVal);
  out.push({
    json: {
      profile,
      matching_key: String(keyVal).trim(),
      qty: Number.isFinite(qtyNum) ? qtyNum : 0,
      raw: r
    }
  });
}

return out;

