const items = $input.all();
let updated_count = 0;
let skipped_count = 0;
let not_found_count = 0;
let error_count = 0;
const run_id = items[0].json.run_id;

for (const item of items) {
  const status = item.json.status || '';
  if (status === 'updated') updated_count++;
  else if (status === 'skipped_unchanged') skipped_count++;
  else if (status === 'not_found') not_found_count++;
  else if (status === 'error') error_count++;
}

let final_status = 'success';
if (error_count > 0) {
  final_status = updated_count > 0 ? 'partial_failed' : 'failed';
}

return [{
  json: {
    run_id,
    updated_count,
    skipped_count,
    not_found_count,
    error_count,
    status: final_status,
    error_summary: {
      top_level: "ok",
      message: error_count > 0 ? "Noen varer feilet" : "Ingen feil"
    }
  }
}];

